mapper.select:
SELECT

FROM crm_relation r
LEFT JOIN crm_customer linked_customer ON r.customer_id = linked_customer.customer_id
LEFT JOIN crm_customer source_customer ON r.source_customer_id = source_customer.customer_id
WHERE r.status = 1
  AND r.create_user_id = #{ownerUserId}

    AND (
        LOWER(COALESCE(r.name, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
        OR LOWER(COALESCE(r.phone, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
        OR LOWER(COALESCE(r.wechat, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
        OR LOWER(COALESCE(r.email, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
        OR LOWER(COALESCE(linked_customer.company_name, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
        OR LOWER(COALESCE(r.remark, '')) LIKE LOWER(CONCAT('%', #{query.keyword}, '%'))
    )


    AND r.relation_type = #{query.relationType}


    AND r.source = #{query.source}


    AND r.source_customer_id = #{query.sourceCustomerId}


    AND r.customer_id = #{query.customerId}


    AND r.source_contact_id = #{query.sourceContactId}

ORDER BY r.update_time DESC NULLS LAST, r.create_time DESC NULLS LAST, r.relation_id DESC
